#include <string>
#include <iostream>
using namespace std;
int n;
string name[21], s[201];
int a[110]; 
int main() {
    cin >> n;
    int b=0;
    for (int k=1;k<=n;k++)
        {
            for (int i = 1; i <= n; i++) {
                cin >> name[i] >> s[i];
            }
            for(int i=1;i<n;i++){
                for(int j=0;j<n-3;j++){
                    if((s[j]=="s")&&(s[j+1]=="o")&&(s[j+2]=="s"))
                    {
                        a[i]+=1;
                    }
                }
                if(a[i]>b){
                    b=a[i];
                } 
            }
         }
    for (int i=1;i<=n;i++) {
        if(a[i]==b)
        {
            cout<<name[i]<<" ";
        }
    }
    cout<<endl;
    cout<<b;
    return 0;
}
